package problems;

import java.util.Arrays;

public class productOfArrayExceptItself {

    public static void main(String[] args) {
        int[] nums = {1, 2, 3, 4};
        System.out.println("Product of elements except self: " + productOfArrayExceptItself(nums));
    }

    /**
     * Calculate product of array except self using prefix/suffix products.
     * O(n) time, O(1) space (excluding output array).
     * 
     * Algorithm:
     * 1. First pass (left to right): Store prefix products in result array
     * 2. Second pass (right to left): Multiply by suffix products
     * 
     * Key insight: answer[i] = (product of all elements before i) * (product of all elements after i)
     * 
     * Example: [1,2,3,4]
     * After prefix pass:  [1, 1, 2, 6]
     * After suffix pass:  [24, 12, 8, 6]
     */
    public static String productOfArrayExceptItself(int[] nums) {
        int n = nums.length;
        int[] ans = new int[n];
        Arrays.fill(ans, 1);

        // Build prefix products in result array
        // ans[i] will contain product of all elements before i
        for (int i = 1; i < n; i++) {
            ans[i] = ans[i - 1] * nums[i - 1];
        }

        // Multiply by suffix products
        // post maintains product of all elements after current index
        int post = 1;
        for (int j = n - 1; j >= 0; j--) {
            ans[j] *= post;
            post *= nums[j];
        }

        return Arrays.toString(ans);
    }
}

// Example:
// Input: nums = [1,2,3,4]
// Output: [24,12,8,6]
// Explanation:
// ans[0] = 2*3*4 = 24
// ans[1] = 1*3*4 = 12
// ans[2] = 1*2*4 = 8
// ans[3] = 1*2*3 = 6

// Time Complexity: O(n) - two passes through array
// Space Complexity: O(1) - excluding output array
